said so, I don't want to hold this PR if this can get unprivileged builds faster into OpenShift.

If you'd like to consider the alternative way I suggested, these are the changes I added to `run.go` (it is an old patch I've used for playing with the FUSE filesystem+dropping namespaces) to get buildah running in a container.

For simplicity I've hardcoded `rootless` to `true`.

In addition to the patch I needed:

- this change in runc: https://github.com/opencontainers/runc/pull/1832
- and I've manually created an userNS with the full range `0 0 4294967295` so that root could gain again all the capabilities in the namespace before running buildah.  This should be also possible to add to the new re-exec code.

```
diff --git a/run.go b/run.go
index 97d247fd..50b5b2f8 100644
--- a/run.go
+++ b/run.go
@@ -797,6 +797,7 @@ func setupNamespaces(g *generate.Generator, namespaceOptions NamespaceOptions, i

 // Run runs the specified command in the container's root filesystem.
 func (b *Builder) Run(command []string, options RunOptions) error {
+	rootless := true
 	var user specs.User
 	p, err := ioutil.TempDir("", Package)
 	if err != nil {
@@ -817,6 +818,44 @@ func (b *Builder) Run(command []string, options RunOptions) error {
 	gp := generate.New()
 	g := &gp

+	if rootless {
+		g.RemoveMount("/dev/pts")
+		devPts := specs.Mount{
+			Destination: "/dev/pts",
+			Type:        "devpts",
+			Source:      "devpts",
+			Options:     []string{"nosuid", "noexec", "newinstance", "ptmxmode=0666", "mode=0620"},
+		}
+		g.AddMount(devPts)
+
+		g.RemoveMount("/sys")
+		sysMnt := specs.Mount{
+			Destination: "/sys",
+			Type:        "bind",
+			Source:      "/sys",
+			Options:     []string{"nosuid", "noexec", "nodev", "ro", "rbind"},
+		}
+		g.AddMount(sysMnt)
+
+		g.RemoveMount("/proc")
+		procMnt := specs.Mount{
+			Destination: "/proc",
+			Type:        "bind",
+			Source:      "/proc",
+			Options:     []string{"nosuid", "noexec", "nodev", "rw", "rbind"},
+		}
+		g.AddMount(procMnt)
+
+		g.RemoveMount("/dev/mqueue")
+		mqueueMnt := specs.Mount{
+			Destination: "/dev/mqueue",
+			Type:        "bind",
+			Source:      "/dev/mqueue",
+			Options:     []string{"nosuid", "noexec", "nodev", "rw", "rbind"},
+		}
+		g.AddMount(mqueueMnt)
+	}
+
 	for _, envSpec := range append(b.Env(), options.Env...) {
 		env := strings.SplitN(envSpec, "=", 2)
 		if len(env) > 1 {
@@ -854,8 +893,10 @@ func (b *Builder) Run(command []string, options RunOptions) error {
 		}
 	}()

-	setupMaskedPaths(g)
-	setupReadOnlyPaths(g)
+	if !rootless {
+		setupMaskedPaths(g)
+		setupReadOnlyPaths(g)
+	}

 	g.SetRootPath(mountPoint)

@@ -875,7 +916,7 @@ func (b *Builder) Run(command []string, options RunOptions) error {
 		return err
 	}

-	if configureUTS {
+	if !rootless && configureUTS {
 		if options.Hostname != "" {
 			g.SetHostname(options.Hostname)
 		} else if b.Hostname() != "" {
@@ -900,9 +941,16 @@ func (b *Builder) Run(command []string, options RunOptions) error {

 	// Now grab the spec from the generator.  Set the generator to nil so that future contributors
 	// will quickly be able to tell that they're supposed to be modifying the spec directly from here.
+	if rootless {
+		g.ClearLinuxNamespaces()
+	}
 	spec := g.Spec()
 	g = nil

+	if rootless {
+		spec.Linux.Resources = nil
+	}
+
 	// Remove capabilities if not running as root
 	if user.UID != 0 {
 		var caplist []string
@@ -1075,6 +1123,8 @@ func runUsingRuntimeMain() {
 }

 func runUsingRuntime(options RunOptions, configureNetwork bool, configureNetworks []string, spec *specs.Spec, rootPath, bundlePath, containerName string) (wstatus unix.WaitStatus, err error) {
+	rootless := true
+
 	// Lock the caller to a single OS-level thread.
 	runtime.LockOSThread()

@@ -1170,6 +1220,9 @@ func runUsingRuntime(options RunOptions, configureNetwork bool, configureNetwork
 	// Build the commands that we'll execute.
 	pidFile := filepath.Join(bundlePath, "pid")
 	args := append(append(append(options.Args, "create", "--bundle", bundlePath, "--pid-file", pidFile), moreCreateArgs...), containerName)
+	if rootless {
+		args = append(append(append(options.Args, "--rootless=true", "create", "--bundle", bundlePath, "--pid-file", pidFile, "--no-new-keyring"), moreCreateArgs...), containerName)
+	}
 	create := exec.Command(runtime, args...)
 	create.Dir = bundlePath
 	stdin, stdout, stderr := getCreateStdio()
